const products = [
  {
    name: "iPhone 16",
    price: 999,
    old: 1200,
    img: "data:image/jpeg;base64,"
  },
  {
    name: "Gaming Laptop",
    price: 1299,
    old: 1500,
    img: "data:image/jpeg;base64,"
  },
  {
    name: "Headphones",
    price: 89,
    old: 120,
    img: "data:image/jpeg;base64,"
  },
  {
    name: "Smart Watch",
    price: 149,
    old: 220,
    img: "data:image/jpeg;base64,"
  },
  {
    name: "Camera",
    price: 699,
    old: 900,
    img: "data:image/jpeg;base64,"
  },
  {
    name: "Sneakers",
    price: 79,
    old: 120,
    img: "data:image/jpeg;base64,"
  }
];

const container = document.getElementById("products");
let cart = 0;

products.forEach((p) => {
  container.innerHTML += `
    <div class="card">
      <img src="${p.img}" alt="${p.name}">
      <div class="info">
        <h3>${p.name}</h3>
        <div>
          <span class="price">$${p.price}</span>
          <span class="old">$${p.old}</span>
        </div>
        <button class="add-btn" type="button">Add To Cart</button>
      </div>
    </div>
  `;
});

document.addEventListener("click", (e) => {
  if (e.target.classList.contains("add-btn")) {
    cart++;
    document.querySelector(".cart-count").innerText = cart;
  }
});

let time = 10800;
setInterval(() => {
  let h = Math.floor(time / 3600);
  let m = Math.floor((time % 3600) / 60);
  let s = time % 60;
  document.getElementById("timer").innerText = `${String(h).padStart(2, "0")}:
${String(m).padStart(2, "0")}:
${String(s).padStart(2, "0")}`;
  time--;
}, 1000);
